import base64

def descargar_pdf_js(pdf_bytes, nombre_archivo):
    """Inyecta JS para descargar el PDF con el nombre correcto, sin depender de Streamlit."""
    b64 = base64.b64encode(pdf_bytes).decode()
    js_code = f"""
    <script>
    (function(){{
        var byteChars = atob('{b64}');
        var byteNums = new Array(byteChars.length);
        for (var i = 0; i < byteChars.length; i++) {{
            byteNums[i] = byteChars.charCodeAt(i);
        }}
        var byteArray = new Uint8Array(byteNums);
        var blob = new Blob([byteArray], {{type: 'application/pdf'}});
        var url = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url;
        a.download = '{nombre_archivo}';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }})();
    </script>
    """
    return js_code

class PDFReport(FPDF):
    def header(self):
        self.set_font('helvetica', 'B', 15)
        self.cell(0, 10, 'Reporte de Monitoreo Ambiental - FADITEX', 0, 1, 'C')
        self.ln(5)

    def footer(self):
        self.set_y(-15)
        self.set_font('helvetica', 'I', 8)
        self.cell(0, 10, f'Pagina {self.page_no()}/{{nb}}', 0, 0, 'C')

def generar_pdf_reporte(df, fecha_inicio, fecha_fin):
    MAX_FILAS_PDF = 500  # limite para que el PDF no exceda los limites de Streamlit
    
    pdf = PDFReport()
    pdf.alias_nb_pages()
    pdf.add_page()
    pdf.set_font('helvetica', '', 11)
    
    # ----- Informacion General -----
    pdf.set_font('helvetica', 'B', 12)
    pdf.cell(0, 10, 'Informacion General', 0, 1)
    pdf.set_font('helvetica', '', 11)
    fecha_i_str = fecha_inicio.strftime("%d/%m/%Y")
    fecha_f_str = fecha_fin.strftime("%d/%m/%Y")
    pdf.cell(0, 8, f'Periodo evaluado: {fecha_i_str} al {fecha_f_str}', 0, 1)
    pdf.cell(0, 8, f'Total de registros analizados: {len(df)}', 0, 1)
    pdf.ln(5)
    
    if df.empty:
        pdf.cell(0, 10, 'No se encontraron datos registrados para este periodo.', 0, 1)
        return bytes(pdf.output())
    
    # ----- Resumen Estadistico -----
    pdf.set_font('helvetica', 'B', 12)
    pdf.cell(0, 10, 'Resumen Estadistico por Sensor', 0, 1)
    
    cols_sensor = ['co2', 'humedad', 'ruido', 'temperatura', 'tvoc']
    unidades = {'co2': 'ppm', 'humedad': '%', 'ruido': 'dB', 'temperatura': 'C', 'tvoc': 'ppb'}
    est_df = df[cols_sensor].describe().T[['min', 'mean', 'max']]
    
    pdf.set_fill_color(200, 220, 255)
    pdf.set_font('helvetica', 'B', 10)
    pdf.cell(40, 8, 'Parametro', 1, 0, 'C', 1)
    pdf.cell(40, 8, 'Minimo', 1, 0, 'C', 1)
    pdf.cell(40, 8, 'Promedio', 1, 0, 'C', 1)
    pdf.cell(40, 8, 'Maximo', 1, 1, 'C', 1)
    
    pdf.set_font('helvetica', '', 10)
    for idx, row in est_df.iterrows():
        nombre = str(idx).upper()
        unidad = unidades.get(str(idx), '')
        pdf.cell(40, 8, f'{nombre} ({unidad})', 1, 0, 'C')
        pdf.cell(40, 8, f'{row["min"]:.1f}', 1, 0, 'C')
        pdf.cell(40, 8, f'{row["mean"]:.1f}', 1, 0, 'C')
        pdf.cell(40, 8, f'{row["max"]:.1f}', 1, 1, 'C')
    
    pdf.ln(5)
    
    # ----- Incidencias -----
    if 'Estado' in df.columns:
        incidencias = df[df['Estado'] == 'Incidencia']
        total_inc = len(incidencias)
        pdf.set_font('helvetica', 'B', 12)
        pdf.cell(0, 10, f'Incidencias Detectadas (Riesgo Alto): {total_inc}', 0, 1)
        pdf.set_font('helvetica', '', 10)
        
        if not incidencias.empty:
            muestra = incidencias.head(MAX_FILAS_PDF)
            pdf.cell(0, 8, f'Detalle de las primeras {len(muestra)} incidencias del periodo:', 0, 1)
            
            pdf.set_fill_color(255, 200, 200)
            pdf.set_font('helvetica', 'B', 9)
            pdf.cell(42, 8, 'Fecha y Hora', 1, 0, 'C', 1)
            pdf.cell(20, 8, 'Riesgo', 1, 0, 'C', 1)
            pdf.cell(22, 8, 'CO2', 1, 0, 'C', 1)
            pdf.cell(22, 8, 'Temp', 1, 0, 'C', 1)
            pdf.cell(22, 8, 'Ruido', 1, 0, 'C', 1)
            pdf.cell(22, 8, 'TVOC', 1, 1, 'C', 1)
            
            pdf.set_font('helvetica', '', 9)
            for _, row in muestra.iterrows():
                ts_str = str(row['Timestamp'])[:19]
                riesgo_str = f"{row.get('Riesgo', 100)}%" if 'Riesgo' in row else 'Alta'
                pdf.cell(42, 8, ts_str, 1, 0, 'C')
                pdf.cell(20, 8, riesgo_str, 1, 0, 'C')
                pdf.cell(22, 8, f'{row["co2"]:.0f}', 1, 0, 'C')
                pdf.cell(22, 8, f'{row["temperatura"]:.1f}', 1, 0, 'C')
                pdf.cell(22, 8, f'{row["ruido"]:.1f}', 1, 0, 'C')
                pdf.cell(22, 8, f'{row["tvoc"]:.0f}', 1, 1, 'C')
            
            if total_inc > MAX_FILAS_PDF:
                pdf.set_font('helvetica', 'I', 9)
                omitidas = total_inc - MAX_FILAS_PDF
                pdf.cell(0, 8, f'Nota: {omitidas} incidencias adicionales omitidas. Descarga el CSV para el detalle completo.', 0, 1)

    return bytes(pdf.output())

